-- 4) Consulta rápida para confirmar

SELECT
    e.codigo,
    e.designacao,
    fe.codigo_familia,
    fe.nome AS familia,
    l.codigo AS localizacao,
    f.nome_empresa AS fornecedor,
    f.tipo_fornecedor
FROM equipamentos e
INNER JOIN familias_equipamento fe
    ON fe.id_familia_equipamento = e.id_familia_equipamento
INNER JOIN localizacoes l
    ON l.id_localizacao = e.id_localizacao
LEFT JOIN equipamentos_fornecedores ef
    ON ef.id_equipamento = e.id_equipamento
   AND ef.isActive = 1
LEFT JOIN fornecedores f
    ON f.id_fornecedor = ef.id_fornecedor
WHERE e.isActive = 1
ORDER BY e.codigo, f.tipo_fornecedor;
